cd "$(cat /tmp/wsdir | cut -d= -f2)"; python3 -c "
import re
lines=open('memory/q_detail.txt').read().split('\n')
# find header lines and their content
blocks=[]
cur=None
for i,l in enumerate(lines):
    if l.startswith('### '):
        cur={'h':l,'start':i,'text':[]}
        blocks.append(cur)
    elif cur is not None:
        cur['text'].append(l)
kw=re.compile(r'AFCON|Africa Cup|Cup of Nations|Morocco|Senegal',re.I)
for b in blocks:
    body=' '.join(b['text'][:4])
    if kw.search(body) or kw.search(b['h']):
        print(b['h'])
        print('  Q:', (b['text'][0] if b['text'] else '')[:160])
"

