lines=open('memory/q_detail.txt').read().split('\n')
blocks=[]; cur=None
for i,l in enumerate(lines):
    if l.startswith('### '):
        cur={'h':l,'text':[]}; blocks.append(cur)
    elif cur is not None: cur['text'].append(l)
kw=re.compile(r'AFCON|Africa Cup|Cup of Nations|\bSenegal\b|\bMorocco\b|Golden Boot|top scorer',re.I)
for b in blocks:
    body=' '.join(b['text'][:5])
    if kw.search(body) or kw.search(b['h']):
        print(b['h'])
        for t in b['text'][:3]:
            if t.strip(): print('   ', t[:170])
        print()
"

